import React from "react";
import type { RoundStatus } from "../types/crash";

function stateClass(status: RoundStatus | "IDLE"): string {
  if (status === "BETTING_OPEN") return "state-betting";
  if (status === "IN_PROGRESS") return "state-live";
  if (status === "CRASHED") return "state-crashed";
  if (status === "SETTLED") return "state-settled";
  return "state-idle";
}

export function MultiplierDisplay({ multiplier, status }: { multiplier: string; status: RoundStatus | "IDLE" }) {
  return (
    <div data-testid="multiplier-display" className={`multiplier ${stateClass(status)}`}>
      {multiplier}x
    </div>
  );
}
